-- dev-seed-cleanup.sql — removes EVERYTHING dev-seed.sql created, plus any
-- side effects (feed items emitted by triggers for seed actors). Safe to run
-- any time; matches only the reserved seed UUIDs.

delete from public.class_enrollments
where class_id in ('22222222-2222-4222-8222-222222222201','22222222-2222-4222-8222-222222222202','22222222-2222-4222-8222-222222222203')
   or user_id in ('11111111-1111-4111-8111-111111111101','11111111-1111-4111-8111-111111111102','11111111-1111-4111-8111-111111111103','11111111-1111-4111-8111-111111111104');

delete from public.class_sessions
where class_id in ('22222222-2222-4222-8222-222222222201','22222222-2222-4222-8222-222222222202','22222222-2222-4222-8222-222222222203');

delete from public.classes
where id in ('22222222-2222-4222-8222-222222222201','22222222-2222-4222-8222-222222222202','22222222-2222-4222-8222-222222222203');

delete from public.provider_reviews
where provider_user_id in ('11111111-1111-4111-8111-111111111101','11111111-1111-4111-8111-111111111102','11111111-1111-4111-8111-111111111103','11111111-1111-4111-8111-111111111104')
   or reviewer_id      in ('11111111-1111-4111-8111-111111111101','11111111-1111-4111-8111-111111111102','11111111-1111-4111-8111-111111111103','11111111-1111-4111-8111-111111111104');

delete from public.class_providers
where user_id in ('11111111-1111-4111-8111-111111111101','11111111-1111-4111-8111-111111111102','11111111-1111-4111-8111-111111111103','11111111-1111-4111-8111-111111111104');

-- trigger-emitted feed items (pro_verified, player_joined, …) for seed actors
delete from public.feed_items
where actor_id in ('11111111-1111-4111-8111-111111111101','11111111-1111-4111-8111-111111111102','11111111-1111-4111-8111-111111111103','11111111-1111-4111-8111-111111111104');

delete from public.profiles
where id in ('11111111-1111-4111-8111-111111111101','11111111-1111-4111-8111-111111111102','11111111-1111-4111-8111-111111111103','11111111-1111-4111-8111-111111111104');

delete from auth.users
where id in ('11111111-1111-4111-8111-111111111101','11111111-1111-4111-8111-111111111102','11111111-1111-4111-8111-111111111103','11111111-1111-4111-8111-111111111104');
